在一个无向带权图中，若使用 Prim 算法从顶点 0 开始构造最小生成树（边权均为正整数，且graph[u][v]
== 0表⽰无边），下列代码中横线处应填入（ ）。

```cpp
int prim(vector<vector<int>>& graph, int n) {
    vector<bool> inMST(n, false);
    vector<int> minEdge(n, INT_MAX);
    minEdge[0] = 0;
    int result = 0;
    for (int i = 0; i < n; i++) {
        int u = -1;
        for (int j = 0; j < n; j++)
        if (!inMST[j] && (u == -1 || minEdge[j] < minEdge[u]))
        u = j;
        inMST[u] = true;
        result += minEdge[u];
        for (int v = 0; v < n; v++)
        if (__________) // 在此处填入选项
        minEdge[v] = graph[u][v];
    }
    return result;
}
```

在64位操作系统下（LP64 / LLP64 模型），下面代码的输出结果是（）。

```cpp
#include <iostream>
using namespace std;
int main() {
    int a[4] = {1, 2, 3, 4};
    int (*p)[4] = &a;
    int *q = a;
    cout << sizeof(a) << " ";
    cout << sizeof(p) << " ";
    cout << sizeof(p + 1) << " ";
    cout << sizeof(q + 1) << " ";
    cout << (p + 1) - p << " ";
    cout << (q + 1) - q << endl;
}
